export const shortnameToUnicode = (str: string): string =>
  str.replace(/:[w+-]+:/g, (shortname) => shortnameToUnicodeMap[shortname] || shortname);

export const toShort = (str: string): string => {
  const sorted = Object.keys(unicodeToShortnameMap).sort((a, b) => b.length - a.length);
  for (const unicode of sorted) {
    if (str.includes(unicode)) {
      str = str.split(unicode).join(unicodeToShortnameMap[unicode]);
    }
  }
  return str;
};
